                padding: "12px 24px",
                borderRadius: 999,
                border: "none",
                background: "linear-gradient(135deg, #12355b, #1d6fa5)",
                color: "white",
                fontWeight: 700,
                cursor:
                  conceptAnswers[conceptIndex] === undefined
                    ? "not-allowed"
                    : "pointer",
                opacity: conceptAnswers[conceptIndex] === undefined ? 0.6 : 1,
                boxShadow: "0 4px 10px rgba(0,0,0,0.08)"
