function EkgQuiz({ onComplete }) {
  const [mode, setMode] = useState("quiz");
  const [questions, setQuestions] = useState(() => shuffleQuestionSet(ekgQuestions));
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [answers, setAnswers] = useState({});
  const [showResults, setShowResults] = useState(false);

  const currentQuestion = questions[index];
  const selected = answers[index];
  const isAnswered = selected !== undefined;

  const restartQuiz = () => {
    setQuestions(shuffleQuestionSet(ekgQuestions));
    setIndex(0);
    setScore(0);
    setAnswers({});
    setShowResults(false);
  };

  const modeToggle = (
    <div
      style={{
        display: "flex",
        justifyContent: "center",
        gap: 12,
        flexWrap: "wrap",
        marginBottom: 20
      }}
    >
      <button
        onClick={() => setMode("basics")}
        style={{
          padding: "10px 20px",
          borderRadius: 999,
          border: "none",
          background:
            mode === "basics"
              ? "linear-gradient(135deg, #12355b, #1d6fa5)"
              : "linear-gradient(135deg, #dbeafe, #eff6ff)",
          color: mode === "basics" ? "white" : "#12355b",
          fontWeight: 700,
          cursor: "pointer",
          boxShadow: "0 4px 10px rgba(0,0,0,0.08)"
        }}
      >
        EKG Basics
      </button>
      <button
        onClick={() => setMode("quiz")}
        style={{
          padding: "10px 20px",
          borderRadius: 999,
          border: "none",
          background:
            mode === "quiz"
              ? "linear-gradient(135deg, #12355b, #1d6fa5)"
              : "linear-gradient(135deg, #dbeafe, #eff6ff)",
          color: mode === "quiz" ? "white" : "#12355b",
          fontWeight: 700,
          cursor: "pointer",
          boxShadow: "0 4px 10px rgba(0,0,0,0.08)"
        }}
      >
        EKG Quiz
      </button>
    </div>
  );

  if (mode === "basics") {
    return (
      <div>
        {modeToggle}
        <EkgBasics />
      </div>
    );
  }

  if (showResults) {
    return (
      <div style={{ padding: 20 }}>
        {modeToggle}
        <div style={{
          background: "rgba(255,255,255,0.92)",
          borderRadius: 24,
          padding: 28,
          boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
          maxWidth: 900,
          margin: "0 auto",
          textAlign: "center"
        }}>
          <h2 style={{ color: "#12355b", marginTop: 0 }}>EKG Waveform Quiz Complete</h2>
          <p style={{ fontSize: 20, color: "#1e293b" }}>
            Your score: {score} / {questions.length}
          </p>
          <p style={{ color: "#4f6275" }}>Practice recognizing common rhythms and keep reinforcing the pattern.</p>
          <button
            onClick={restartQuiz}
            style={{
              padding: "12px 24px",
              borderRadius: 999,
              border: "none",
              background: "linear-gradient(135deg, #12355b, #1d6fa5)",
              color: "white",
              fontWeight: 700,
              cursor: "pointer"
            }}
          >
            Restart EKG Quiz
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ padding: 20 }}>
      {modeToggle}
      <div style={{
        background: "rgba(255,255,255,0.9)",
        borderRadius: 24,
        padding: 28,
        boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
        maxWidth: 980,
        margin: "0 auto"
      }}>
        <div style={{ textAlign: "center", marginBottom: 20 }}>
          <h2 style={{ color: "#12355b", marginBottom: 8 }}>EKG Waveform Quiz</h2>
          <p style={{ color: "#4f6275", margin: 0 }}>
            Learn to recognize common rhythms by pattern. Read the strip, choose the rhythm, and review the explanation.
          </p>
        </div>

        <div style={{
          display: "flex",
          justifyContent: "space-between",
          gap: 10,
          flexWrap: "wrap",
          marginBottom: 20
        }}>
          <div style={{
            padding: "10px 16px",
            borderRadius: 999,
            background: "#eff6ff",
            color: "#12355b",
            fontWeight: 700
          }}>
            Question {index + 1} / {questions.length}
          </div>
          <div style={{
            padding: "10px 16px",
            borderRadius: 999,
            background: "#ecfeff",
            color: "#0f766e",
            fontWeight: 700
          }}>
            Score: {score}
          </div>
        </div>

        <EkgWaveform type={currentQuestion.waveformType} />

        <div style={{ color: "#12355b", marginBottom: 18 }}>
          <div style={{ fontSize: 22, fontWeight: 700 }}>{currentQuestion.question}</div>
        </div>

        {currentQuestion.options.map((opt, i) => {
          const isCorrectOption = i === currentQuestion.answer;
          const isSelectedWrong = isAnswered && i === selected && selected !== currentQuestion.answer;
          return (
            <button
              key={i}
              onClick={() => {
                if (isAnswered) return;
                setAnswers((prev) => ({ ...prev, [index]: i }));
                if (i === currentQuestion.answer) {
                  setScore((prev) => prev + 1);
                }
              }}
              style={{
                width: "100%",
                textAlign: "left",
                padding: "14px 16px",
                marginBottom: 12,
                borderRadius: 12,
                border:
                  isCorrectOption && isAnswered
                    ? "2px solid green"
                    : isSelectedWrong
                    ? "2px solid red"
                    : "1px solid #cbd5e1",
                background:
                  isCorrectOption && isAnswered
                    ? "#d9f7d9"
                    : isSelectedWrong
                    ? "#fee2e2"
                    : "#f8fafc",
                color: "#1e293b",
                fontSize: 16,
                fontWeight: 600,
                cursor: isAnswered ? "default" : "pointer",
                boxShadow: "0 2px 6px rgba(0,0,0,0.03)"
              }}
            >
              {String.fromCharCode(65 + i)}. {opt}
            </button>
          );
        })}

        {isAnswered && (
          <div
            style={{
              marginTop: 8,
              padding: "12px 14px",
              borderRadius: 12,
              background: selected === currentQuestion.answer ? "#eff6ff" : "#fff7ed",
              color: selected === currentQuestion.answer ? "#1d4ed8" : "#9a3412",
              border: selected === currentQuestion.answer ? "1px solid #bfdbfe" : "1px solid #fdba74",
              fontWeight: 600
            }}
          >
            <div>{currentQuestion.explanation}</div>
            <div style={{ marginTop: 8, fontWeight: 500 }}>Why this matters: {currentQuestion.whyItMatters}</div>
          </div>
        )}

        <div style={{ textAlign: "center", marginTop: 20 }}>
          <button
            onClick={() => {
              if (!isAnswered) return;
              if (index + 1 === questions.length) {
                onComplete && onComplete(score + (selected === currentQuestion.answer ? 0 : 0), questions.length);
                setShowResults(true);
              } else {
                setIndex((prev) => prev + 1);
              }
            }}
            style={{
              padding: "12px 24px",
              borderRadius: 999,
              border: "none",
              background: "linear-gradient(135deg, #12355b, #1d6fa5)",
              color: "white",
              fontWeight: 700,
              cursor: !isAnswered ? "not-allowed" : "pointer",
              opacity: !isAnswered ? 0.6 : 1,
              boxShadow: "0 4px 10px rgba(0,0,0,0.08)"
            }}
          >
            {index + 1 === questions.length ? "Finish Quiz" : "Next Question"}
          </button>
        </div>
      </div>
    </div>
  );
}

