function MuscleQuiz({ onComplete }) {
  const [current, setCurrent] = React.useState(0);
  const [selected, setSelected] = React.useState(null);
  const [score, setScore] = React.useState(0);
  const [showResults, setShowResults] = React.useState(false);

  const question = muscleQuizQuestions[current];
  const total = muscleQuizQuestions.length;
  const isAnswered = selected !== null;

  const restartQuiz = () => {
    setCurrent(0);
    setSelected(null);
    setScore(0);
    setShowResults(false);
  };

  if (showResults) {
    const percent = Math.round((score / total) * 100);
    return (
      <div style={{ padding: 20 }}>
        <div
          style={{
            background: "rgba(255,255,255,0.92)",
            borderRadius: 24,
            padding: 28,
            boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
            maxWidth: 900,
            margin: "0 auto",
            textAlign: "center"
          }}
        >
          <h2 style={{ color: "#12355b", marginTop: 0 }}>Muscle Quiz Complete</h2>
          <p style={{ fontSize: 20, color: "#1e293b" }}>
            Your score: {score} / {total}
          </p>
          <p style={{ color: "#4f6275", marginBottom: 20 }}>
            Accuracy: {percent}%
          </p>
          <button
            onClick={restartQuiz}
            style={{
              padding: "12px 24px",
              borderRadius: 999,
              border: "none",
              background: "linear-gradient(135deg, #12355b, #1d6fa5)",
              color: "white",
              fontWeight: 700,
              cursor: "pointer"
            }}
          >
            Restart Muscle Quiz
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ padding: 20 }}>
      <div
        style={{
          background: "rgba(255,255,255,0.9)",
          borderRadius: 24,
          padding: 28,
          boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
          maxWidth: 900,
          margin: "0 auto"
        }}
      >
        <div style={{ textAlign: "center", marginBottom: 20 }}>
          <h2 style={{ color: "#12355b", marginBottom: 8 }}>Muscle Quiz</h2>
          <p style={{ color: "#4f6275", margin: 0 }}>
            Test your knowledge of the major muscles used in your anterior muscle practice game.
          </p>
        </div>

        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            gap: 10,
            flexWrap: "wrap",
            marginBottom: 20
          }}
        >
          <div
            style={{
              padding: "10px 16px",
              borderRadius: 999,
              background: "#eff6ff",
              color: "#12355b",
              fontWeight: 700
            }}
          >
            Question {current + 1} / {total}
          </div>
          <div
            style={{
              padding: "10px 16px",
              borderRadius: 999,
              background: "#ecfeff",
              color: "#0f766e",
              fontWeight: 700
            }}
          >
            Score: {score}
          </div>
          <div
            style={{
              padding: "10px 16px",
              borderRadius: 999,
              background: "#f8fafc",
              color: "#475569",
              fontWeight: 700
            }}
          >
            Muscles
          </div>
        </div>

        <div style={{ color: "#12355b", marginBottom: 18 }}>
          <div style={{ fontSize: 24, fontWeight: 700 }}>{question.question}</div>
        </div>

        {question.options.map((opt, i) => {
          const isCorrectOption = i === question.answer;
          const isSelectedWrong = isAnswered && i === selected && selected !== question.answer;
          return (
            <button
              key={i}
              onClick={() => {
                if (isAnswered) return;
                setSelected(i);
                if (i === question.answer) {
                  setScore((prev) => prev + 1);
                }
              }}
              style={{
                width: "100%",
                textAlign: "left",
                padding: "14px 16px",
                marginBottom: 12,
                borderRadius: 12,
                border:
                  isCorrectOption && isAnswered
                    ? "2px solid green"
                    : isSelectedWrong
                    ? "2px solid red"
                    : "1px solid #cbd5e1",
                background:
                  isCorrectOption && isAnswered
                    ? "#d9f7d9"
                    : isSelectedWrong
                    ? "#fee2e2"
                    : "#f8fafc",
                color: "#1e293b",
                fontSize: 16,
                fontWeight: 600,
                cursor: isAnswered ? "default" : "pointer",
                boxShadow: "0 2px 6px rgba(0,0,0,0.03)"
              }}
            >
              {String.fromCharCode(65 + i)}. {opt}
            </button>
          );
        })}

        {isAnswered && (
          <div
            style={{
              marginTop: 8,
              padding: "12px 14px",
              borderRadius: 12,
              background: "#eff6ff",
              color: "#1d4ed8",
              border: "1px solid #bfdbfe",
              fontWeight: 600
            }}
          >
            Explanation: {question.explanation}
          </div>
        )}

        <div style={{ textAlign: "center", marginTop: 20 }}>
          <button
            onClick={() => {
              if (!isAnswered) return;
              const isCorrect = selected === question.answer;
              const nextScore = isCorrect ? score + 1 : score;
              if (current + 1 === total) {
                onComplete && onComplete(nextScore, total);
                setScore(nextScore);
                setShowResults(true);
              } else {
                setCurrent((prev) => prev + 1);
                setSelected(null);
              }
            }}
            style={{
              padding: "12px 24px",
              borderRadius: 999,
              border: "none",
              background: "linear-gradient(135deg, #12355b, #1d6fa5)",
              color: "white",
              fontWeight: 700,
              cursor: !isAnswered ? "not-allowed" : "pointer",
              opacity: !isAnswered ? 0.6 : 1
            }}
          >
            {current + 1 === total ? "Finish Quiz" : "Next Question"}
          </button>
        </div>
      </div>
    </div>
  );
}




