  const startedAt = examStartTimesRef.current[examName];
  const timeSeconds = startedAt ? Math.max(1, Math.round((Date.now() - startedAt) / 1000)) : 0;
  delete examStartTimesRef.current[examName];

  setOwnerExamStats((prev) => {
    const current = prev?.[examName] || { started: 0, completed: 0 };
    const next = {
      ...prev,
      [examName]: {
        ...current,
        completed: (current.completed || 0) + 1
      }
    }; //

    localStorage.setItem("ownerExamStats", JSON.stringify(next));
    return next;
  });

  if (typeof window === "undefined" || typeof window.gtag !== "function") {
    return;
  }

  window.gtag("event", "exam_completed", {
    exam_name: examName,
    score: scoreValue,
    total_questions: totalValue,
    completion_rate: totalValue > 0 ? Math.round((scoreValue / totalValue) * 100) : 0
  });

  openSaveScorePrompt(examName, scoreValue, totalValue, timeSeconds);
